175	 * Side-effects of calling this function:
176	 *
177	 * 1. A key gets expired if it reached it's TTL.
178	 * 2. The key's last access time is updated.
179	 * 3. The global keys hits/misses stats are updated (reported in INFO).
180	 * 4. If keyspace notifications are enabled, a "keymiss" notification is fired.
181	 *
182	 * Flags change the behavior of this command:
183	 *
184	 *  LOOKUP_NONE (or zero): No special flags are passed.
185	 *  LOOKUP_NOTOUCH: Don't alter the last access time of the key.
186	 *  LOOKUP_NONOTIFY: Don't trigger keyspace event on key miss.
187	 *  LOOKUP_NOSTATS: Don't increment key hits/misses counters.
188	 *  LOOKUP_WRITE: Prepare the key for writing (delete expired keys even on
189	 *                replicas, use separate keyspace stats and events (TODO)).
190	 *  LOOKUP_NOEXPIRE: Perform expiration check, but avoid deleting the key,
191	 *                   so that we don't have to propagate the deletion.
192	 *
193	 * Note: this function also returns NULL if the key is logically expired but
194	 * still existing, in case this is a replica and the LOOKUP_WRITE is not set.
195	 * Even if the key expiry is master-driven, we can correctly report a key is
196	 * expired on replicas even if the master is lagging expiring our key via DELs
197	 * in the replication link. */
198	kvobj *lookupKey(redisDb *db, robj *key, int flags, dictEntryLink *link) {
199	
200	    kvobj *val = dbFindByLink(db, key->ptr, link);
201	
202	    if (val) {
203	        /* Forcing deletion of expired keys on a replica makes the replica
204	         * inconsistent with the master. We forbid it on readonly replicas, but
205	         * we have to allow it on writable replicas to make write commands
206	         * behave consistently.
207	         *
208	         * It's possible that the WRITE flag is set even during a readonly
209	         * command, since the command may trigger events that cause modules to
210	         * perform additional writes. */
211	        int is_ro_replica = server.masterhost && server.repl_slave_ro;
212	        int expire_flags = 0;
213	        if (flags & LOOKUP_WRITE && !is_ro_replica)
214	            expire_flags |= EXPIRE_FORCE_DELETE_EXPIRED;
215	        if (flags & LOOKUP_NOEXPIRE)
216	            expire_flags |= EXPIRE_AVOID_DELETE_EXPIRED;
217	        if (flags & LOOKUP_ACCESS_EXPIRED)
218	            expire_flags |= EXPIRE_ALLOW_ACCESS_EXPIRED;
219	        if (expireIfNeeded(db, key, val, expire_flags) != KEY_VALID) {
220	            /* The key is no longer valid. */
221	            val = NULL;
222	            if (link) *link = NULL;
223	        }
224	    }
225	
226	    if (val) {
227	        /* Update the access time for the ageing algorithm.
228	         * Don't do it if we have a saving child, as this will trigger
229	         * a copy on write madness. */
230	        if (server.current_client && server.current_client->flags & CLIENT_NO_TOUCH &&
231	            server.executing_client->cmd->proc != touchCommand)
232	            flags |= LOOKUP_NOTOUCH;
233	        if (!hasActiveChildProcess() && !(flags & LOOKUP_NOTOUCH)){
234	            if (server.maxmemory_policy & MAXMEMORY_FLAG_LFU) {
235	                updateLFU(val);
236	            } else {
237	                val->lru = LRU_CLOCK();
238	            }
239	        }
240	
241	        if (!(flags & (LOOKUP_NOSTATS | LOOKUP_WRITE)))
242	            server.stat_keyspace_hits++;
243	        /* TODO: Use separate hits stats for WRITE */
244	    } else {
245	        if (!(flags & (LOOKUP_NONOTIFY | LOOKUP_WRITE)))
246	            notifyKeyspaceEvent(NOTIFY_KEY_MISS, "keymiss", key, db->id);
247	        if (!(flags & (LOOKUP_NOSTATS | LOOKUP_WRITE)))
248	            server.stat_keyspace_misses++;
249	        /* TODO: Use separate misses stats and notify event for WRITE */
250	    }
