624	 * dictDelete() and dictUnlink(), please check the top comment
625	 * of those functions. */
626	static dictEntry *dictGenericDelete(dict *d, const void *key, int nofree) {
627	    dictCmpCache cmpCache = {0};
628	    uint64_t h, idx;
629	    dictEntry *he, *prevHe;
630	    int table;
631	
632	    /* dict is empty */
633	    if (dictSize(d) == 0) return NULL;
634	
635	    h = dictHashKey(d, key, d->useStoredKeyApi);
636	    idx = h & DICTHT_SIZE_MASK(d->ht_size_exp[0]);
637	
638	    /* Rehash the hash table if needed */
639	    _dictRehashStepIfNeeded(d,idx);
640	
641	    keyCmpFunc cmpFunc = dictGetCmpFunc(d);
642	
643	    for (table = 0; table <= 1; table++) {
644	        if (table == 0 && (long)idx < d->rehashidx) continue;
645	        idx = h & DICTHT_SIZE_MASK(d->ht_size_exp[table]);
646	        he = d->ht_table[table][idx];
647	        prevHe = NULL;
648	        while(he) {
649	            void *he_key = dictGetKey(he);
650	            if (key == he_key || cmpFunc(&cmpCache, key, he_key)) {
651	                /* Unlink the element from the list */
652	                if (prevHe)
653	                    dictSetNext(prevHe, dictGetNext(he));
654	                else
655	                    d->ht_table[table][idx] = dictGetNext(he);
656	                if (!nofree) {
657	                    dictFreeUnlinkedEntry(d, he);
658	                }
659	                d->ht_used[table]--;
660	                _dictShrinkIfNeeded(d);
661	                return he;
662	            }
663	            prevHe = he;
664	            he = dictGetNext(he);
665	        }
666	        if (!dictIsRehashing(d)) break;
667	    }
668	    return NULL; /* not found */
669	}
