38	kvobj *kvobjCreate(int type, const sds key, void *ptr, int hasExpire) {
39	    /* Determine embedded key and expiration flags */
40	    serverAssert(key != NULL);
41	    hasExpire = hasExpire || (sdslen(key) >= KEY_SIZE_TO_INCLUDE_EXPIRE_THRESHOLD);
42	    
43	    /* Calculate embedded key size */
44	    size_t key_sds_len = sdslen(key);
45	    char key_sds_type = sdsReqType(key_sds_len);
46	    size_t key_sds_size = sdsReqSize(key_sds_len, key_sds_type);
