48	    /* Compute the base object size */
49	    size_t min_size = sizeof(robj);
50	    if (hasExpire) min_size += sizeof(long long);
51	    min_size += 1 + key_sds_size; /* 1 byte for SDS header size */
52	
53	    /* Allocate object memory */
54	    size_t bufsize = 0;
55	    robj *o = zmalloc_usable(min_size, &bufsize);
56	    o->type = type;
57	    o->encoding = OBJ_ENCODING_RAW;
58	    o->ptr = ptr;
59	    o->refcount = 1;
60	    o->lru = 0;
