545	     * Assert that the provided bucket is the right table. */
546	    int htidx = dictIsRehashing(d) ? 1 : 0;
547	    assert(bucket >= &d->ht_table[htidx][0] &&
548	           bucket <= &d->ht_table[htidx][DICTHT_SIZE_MASK(d->ht_size_exp[htidx])]);
