            dictUseStoredKeyApi((dict *)o->ptr, 1);
            ret = dictAdd((dict*)o->ptr, field, value);
            dictUseStoredKeyApi((dict *)o->ptr, 0);
            if (ret == DICT_ERR) {
                rdbReportCorruptRDB("Duplicate hash fields detected");
