1016	SetExRes hashTypeSetExpiryHT(HashTypeSetEx *exInfo, sds field, uint64_t expireAt) {
1017	    dict *ht = exInfo->hashObj->ptr;
1018	    dictEntry *existingEntry = NULL;
1019	    hfield hfNew = NULL;
1020	
1021	    if ((existingEntry = dictFind(ht, field)) == NULL)
1022	        return HSETEX_NO_FIELD;
1023	
1024	    hfield hfOld = dictGetKey(existingEntry);
1025	    /* Special value of EXPIRE_TIME_INVALID indicates field should be persisted.*/
1026	    if (expireAt == EB_EXPIRE_TIME_INVALID) {
1027	        /* Return error if already there is no ttl. */
1028	        if (hfieldGetExpireTime(hfOld) == EB_EXPIRE_TIME_INVALID)
1029	            return HSETEX_NO_CONDITION_MET;
1030	
1031	        hfieldPersist(exInfo->hashObj, hfOld);
1032	        return HSETEX_OK;
1033	    }
1034	
1035	    /* If field doesn't have expiry metadata attached */
1036	    if (!hfieldIsExpireAttached(hfOld)) {
1037	        /* For fields without expiry, LT condition is considered valid */
1038	        if (exInfo->expireSetCond & (HFE_XX | HFE_GT))
1039	            return HSETEX_NO_CONDITION_MET;
1040	
1041	        /* Delete old field. Below goanna dictSetKey(..,hfNew) */
1042	        hfieldFree(hfOld);
1043	        /* New field with expiration metadata */
1044	        hfNew = hfieldNew(field, sdslen(field), 1);
1045	    } else { /* field has ExpireMeta struct attached */
1046	        uint64_t prevExpire = hfieldGetExpireTime(hfOld);
1047	
1048	        /* If field has valid expiration time, then check GT|LT|NX */
1049	        if (prevExpire != EB_EXPIRE_TIME_INVALID) {
1050	            if (((exInfo->expireSetCond == HFE_GT) && (prevExpire >= expireAt)) ||
1051	                ((exInfo->expireSetCond == HFE_LT) && (prevExpire <= expireAt)) ||
1052	                (exInfo->expireSetCond == HFE_NX) )
1053	                return HSETEX_NO_CONDITION_MET;
1054	
1055	            /* remove old expiry time from hash's private ebuckets */
1056	            dictExpireMetadata *dm = (dictExpireMetadata *) dictMetadata(ht);
1057	            ebRemove(&dm->hfe, &hashFieldExpireBucketsType, hfOld);
1058	
1059	            /* Track of minimum expiration time (only later update global HFE DS) */
1060	            if (exInfo->minExpireFields > prevExpire)
1061	                exInfo->minExpireFields = prevExpire;
1062	
1063	        } else {
1064	            /* field has invalid expiry. No need to ebRemove() */
1065	
1066	            /* Check XX|LT|GT */
1067	            if (exInfo->expireSetCond & (HFE_XX | HFE_GT))
1068	                return HSETEX_NO_CONDITION_MET;
1069	        }
1070	
1071	        /* Reuse hfOld as hfNew and rewrite its expiry with ebAdd() */
1072	        hfNew = hfOld;
1073	    }
1074	
1075	    dictSetKey(ht, existingEntry, hfNew);
1076	
1077	
1078	    /* If expired, then delete the field and propagate the deletion.
1079	     * If replica, continue like the field is valid */
1080	    if (unlikely(checkAlreadyExpired(expireAt))) {
1081	        /* replicas should not initiate deletion of fields */
1082	        propagateHashFieldDeletion(exInfo->db, exInfo->key->ptr, field, sdslen(field));
1083	        hashTypeDelete(exInfo->hashObj, field, 1);
1084	        server.stat_expired_subkeys++;
1085	        return HSETEX_DELETED;
1086	    }
1087	
1088	    if (exInfo->minExpireFields > expireAt)
1089	        exInfo->minExpireFields = expireAt;
1090	
1091	    dictExpireMetadata *dm = (dictExpireMetadata *) dictMetadata(ht);
1092	    ebAdd(&dm->hfe, &hashFieldExpireBucketsType, hfNew, expireAt);
1093	    return HSETEX_OK;
