1182	/*
1183	 * After calling hashTypeSetEx() for setting fields or their expiry, call this
1184	 * function to update global HFE DS.
1185	 */
1186	void hashTypeSetExDone(HashTypeSetEx *ex) {
1187	
1188	    if (hashTypeLength(ex->hashObj, 0) == 0)
1189	        return;
1190	
1191	    /* If minimum HFE of the hash is smaller than expiration time of the
1192	     * specified fields in the command as well as it is smaller or equal
1193	     * than expiration time provided in the command, then the minimum
1194	     * HFE of the hash won't change following this command. */
1195	    if ((ex->minExpire < ex->minExpireFields))
1196	        return;
1197	
1198	    /* Retrieve new expired time. It might have changed. */
1199	    uint64_t newMinExpire = hashTypeGetMinExpire(ex->hashObj, 1 /*accurate*/);
1200	
1201	    /* Calculate the diff between old minExpire and newMinExpire. If it is
1202	     * only few seconds, then don't have to update global HFE DS. At the worst
1203	     * case fields of hash will be active-expired up to few seconds later.
1204	     *
1205	     * In any case, active-expire operation will know to update global
1206	     * HFE DS more efficiently than here for a single item.
1207	     */
1208	    uint64_t diff = (ex->minExpire > newMinExpire) ?
1209	                    (ex->minExpire - newMinExpire) : (newMinExpire - ex->minExpire);
1210	    if (diff < HASH_NEW_EXPIRE_DIFF_THRESHOLD) return;
1211	
1212	    if (ex->minExpire != EB_EXPIRE_TIME_INVALID)
1213	        ebRemove(&ex->db->hexpires, &hashExpireBucketsType, ex->hashObj);
1214	    if (newMinExpire != EB_EXPIRE_TIME_INVALID)
1215	        ebAdd(&ex->db->hexpires, &hashExpireBucketsType, ex->hashObj, newMinExpire);
1216	}
